//! Clean-room reimplementation of the tamarin-prover CLI/console text surface.
//!
//! Unit D of the relicensing effort. Every observable string in this crate was
//! derived from black-box probing of the compiled binary (see
//! `workspace/BEHAVIOR.md` and `workspace/QUERIES.log`); exact output strings
//! (help pages, banners, error texts) are stored as observed-output fixtures and
//! treated as opaque compatibility content. The parsing architecture, flag-table
//! model, and framing assembly are original.
//!
//! Public surface:
//! - [`parse`] : `parse(argv) -> Result<Command, CliError>` — the structured
//!   command, or ready-to-print error text.
//! - [`render_help`] / [`render_version`] : the help pages and version banner.
//! - [`framing`] : the batch-mode output frame around an opaque theory payload.
//! - [`errors`] : renderers for the runtime error lines emitted after parsing.

pub mod modes;
pub mod parse;
pub mod help;
pub mod version;
pub mod framing;
pub mod errors;

pub use errors::CliError;
pub use help::render_help;
pub use modes::Mode;
pub use parse::{parse, Command, Options, RunSpec};
pub use version::{render_version, VersionInfo};

//! Modes and their flag tables.
//!
//! The binary is a multi-mode command. The first token selects a mode by unique
//! prefix match against the mode names; otherwise the default (batch) mode is
//! used and the token is a positional. Each mode recognizes a different set of
//! flags, so the flag table is mode-scoped (a flag valid in one mode is
//! "Unknown" in another — e.g. `--version` outside the default mode).

/// The four invocation modes.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Mode {
    /// Default mode when no mode token is given: analyze/prove theory FILES.
    Batch,
    /// `interactive` — web server; positional WORKDIR.
    Interactive,
    /// `variants` — compute intruder-rule variants; no positional.
    Variants,
    /// `test` — self-test; positional FILES.
    Test,
}

impl Mode {
    /// The three named modes, in the order the help/ambiguity messages list them.
    pub const NAMED: [(&'static str, Mode); 3] = [
        ("interactive", Mode::Interactive),
        ("variants", Mode::Variants),
        ("test", Mode::Test),
    ];

    /// Modes whose named token is a prefix of `token` (empty token matches all).
    pub fn prefix_matches(token: &str) -> Vec<(&'static str, Mode)> {
        Mode::NAMED
            .iter()
            .filter(|(name, _)| name.starts_with(token))
            .copied()
            .collect()
    }
}

/// One recognized flag: its canonical long name, optional short char, whether it
/// accepts a value, and any additional long aliases.
#[derive(Debug, Clone, Copy)]
pub struct FlagSpec {
    pub long: &'static str,
    pub short: Option<char>,
    pub takes_value: bool,
    pub aliases: &'static [&'static str],
}

const fn boolf(long: &'static str, short: Option<char>) -> FlagSpec {
    FlagSpec { long, short, takes_value: false, aliases: &[] }
}
const fn valf(long: &'static str, short: Option<char>) -> FlagSpec {
    FlagSpec { long, short, takes_value: true, aliases: &[] }
}

// The proving/output flag subset shared by the default and interactive modes.
const PROVE_COMMON: &[FlagSpec] = &[
    valf("prove", None),
    valf("lemma", None),
    valf("stop-on-trace", None),
    valf("bound", Some('b')),
    valf("heuristic", None),
    valf("partial-evaluation", None),
    valf("defines", Some('D')),
    boolf("diff", None),
    boolf("quit-on-warning", None),
    boolf("auto-sources", None),
    valf("oraclename", None),
    boolf("oracle-only", None),
    boolf("quiet", None),
    boolf("verbose", Some('v')),
    valf("open-chains", Some('c')),
    valf("saturation", Some('s')),
    valf("derivcheck-timeout", Some('d')),
    boolf("no-reuse", None),
    boolf("no-restrictions", None),
    valf("replication-bound", None),
];

const WITH_TOOLS: &[FlagSpec] = &[
    valf("with-dot", None),
    valf("with-json", None),
    valf("with-maude", None),
];

/// Flags recognized in the default/batch mode (excluding About flags).
pub fn batch_flags() -> Vec<FlagSpec> {
    let mut v: Vec<FlagSpec> = PROVE_COMMON.to_vec();
    v.extend_from_slice(&[
        boolf("no-compress", None),
        boolf("parse-only", None),
        boolf("precompute-only", None),
        valf("output", Some('o')),
        valf("Output", Some('O')),
        valf("output-module", Some('m')),
        FlagSpec { long: "output-json", short: None, takes_value: true, aliases: &["oj"] },
        FlagSpec { long: "output-dot", short: None, takes_value: true, aliases: &["od"] },
    ]);
    v.extend_from_slice(WITH_TOOLS);
    v
}

/// Flags recognized in the interactive mode (excluding About flags).
pub fn interactive_flags() -> Vec<FlagSpec> {
    let mut v = vec![
        valf("port", Some('p')),
        valf("interface", Some('i')),
        valf("image-format", None),
        boolf("debug", None),
        boolf("no-logging", None),
    ];
    v.extend_from_slice(PROVE_COMMON);
    v.extend_from_slice(WITH_TOOLS);
    v
}

/// Flags recognized in the variants mode (excluding About flags).
pub fn variants_flags() -> Vec<FlagSpec> {
    vec![valf("Output", Some('O'))]
}

/// Flags recognized in the test mode (excluding About flags).
pub fn test_flags() -> Vec<FlagSpec> {
    WITH_TOOLS.to_vec()
}

/// The mode-scoped flag table (mode flags first, then About flags). `--version`
/// / `-V` is an About flag only in the default mode.
pub fn flags_for(mode: Mode) -> Vec<FlagSpec> {
    let mut v = match mode {
        Mode::Batch => batch_flags(),
        Mode::Interactive => interactive_flags(),
        Mode::Variants => variants_flags(),
        Mode::Test => test_flags(),
    };
    // About: help everywhere; version only in the default mode.
    v.push(FlagSpec { long: "help", short: Some('?'), takes_value: false, aliases: &[] });
    if mode == Mode::Batch {
        v.push(boolf("version", Some('V')));
    }
    v
}

//! `parse(argv) -> Result<Command, CliError>`.
//!
//! Turns an argument vector into a structured [`Command`] or ready-to-print
//! error text. Parsing is pure (no filesystem access): the two cmdargs-level
//! errors that require the filesystem — the interactive WORKDIR existence check —
//! are surfaced as a [`RunSpec`] the caller can validate with
//! [`crate::errors::directory_does_not_exist`]. The "no input files given" check
//! needs no filesystem and is emitted here.

use crate::errors::{self, CliError};
use crate::modes::{flags_for, FlagSpec, Mode};

/// A structured, actionable command produced by [`parse`].
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Command {
    /// Print the given mode's help page (exit 0).
    Help(Mode),
    /// Print the version banner (exit 0). Only reachable in the default mode.
    Version,
    /// A mode invocation with parsed positionals and options.
    Run(RunSpec),
}

/// A parsed mode invocation.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RunSpec {
    pub mode: Mode,
    /// FILES (batch/test) or the WORKDIR token(s) (interactive).
    pub positional: Vec<String>,
    pub options: Options,
}

/// Recognized flags recorded in encounter order.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct Options {
    /// `(canonical_long_name, value)` per occurrence; `value` is `None` for the
    /// bare form of a value flag and for boolean flags.
    pub flags: Vec<(String, Option<String>)>,
}

impl Options {
    /// True if the boolean/valued flag with this canonical long name was seen.
    pub fn is_set(&self, long: &str) -> bool {
        self.flags.iter().any(|(n, _)| n == long)
    }
    /// All values supplied for a (possibly repeated) flag.
    pub fn values(&self, long: &str) -> Vec<&str> {
        self.flags
            .iter()
            .filter(|(n, _)| n == long)
            .filter_map(|(_, v)| v.as_deref())
            .collect()
    }
}

/// Parse an argument vector (excluding argv[0]/program name).
pub fn parse(argv: &[String]) -> Result<Command, CliError> {
    // 1. Determine mode and the slice of tokens to parse within it.
    let (mode, rest): (Mode, &[String]) = match argv.first() {
        // Truly empty argv is not observable through the oracle; treated as the
        // default-mode no-input case (documented inference).
        None => return Err(errors::no_input_files(Mode::Batch)),
        Some(first) if first.starts_with('-') => (Mode::Batch, argv),
        Some(first) => {
            let matches = Mode::prefix_matches(first);
            match matches.len() {
                1 => (matches[0].1, &argv[1..]),
                0 => (Mode::Batch, argv), // not a mode prefix -> a FILE
                _ => {
                    let names: Vec<&str> = matches.iter().map(|(n, _)| *n).collect();
                    return Err(errors::ambiguous_mode(first, &names));
                }
            }
        }
    };

    // 2. Left-to-right token scan within the chosen mode.
    let table = flags_for(mode);
    let mut options = Options::default();
    let mut positional: Vec<String> = Vec::new();

    for tok in rest {
        if let Some(body) = tok.strip_prefix("--") {
            // Long flag: `--name` or `--name=value`.
            let (name, value) = match body.split_once('=') {
                Some((n, v)) => (n, Some(v.to_string())),
                None => (body, None),
            };
            let spec = lookup_long(&table, name)
                .ok_or_else(|| errors::unknown_flag(&format!("--{name}")))?;
            if !spec.takes_value && value.is_some() {
                return Err(errors::unhandled_argument(tok));
            }
            if let Some(c) = short_circuit(spec.long, mode) {
                return Ok(c);
            }
            options.flags.push((spec.long.to_string(), value));
        } else if tok.len() >= 2 && tok.starts_with('-') && tok != "--" {
            // Short flag: `-x` or `-x<attached value>`.
            let mut chars = tok[1..].chars();
            let c = chars.next().unwrap();
            let attached: String = chars.collect();
            let spec = lookup_short(&table, c)
                .ok_or_else(|| errors::unknown_flag(tok))?;
            if spec.takes_value {
                let value = if attached.is_empty() { None } else { Some(attached) };
                if let Some(cmd) = short_circuit(spec.long, mode) {
                    return Ok(cmd);
                }
                options.flags.push((spec.long.to_string(), value));
            } else {
                // Boolean short flag: only the bare form is recognized here.
                if !attached.is_empty() {
                    return Err(errors::unknown_flag(tok));
                }
                if let Some(cmd) = short_circuit(spec.long, mode) {
                    return Ok(cmd);
                }
                options.flags.push((spec.long.to_string(), None));
            }
        } else {
            // Positional token (a FILE, or the WORKDIR for interactive).
            positional.push(tok.clone());
        }
    }

    // 3. Positional-arity validation that cmdargs performs at parse time.
    // Batch and test require at least one input FILE.
    if matches!(mode, Mode::Batch | Mode::Test) && positional.is_empty() {
        return Err(errors::no_input_files(mode));
    }

    Ok(Command::Run(RunSpec { mode, positional, options }))
}

/// Map an About flag to its terminal command, if it is one.
fn short_circuit(long: &str, mode: Mode) -> Option<Command> {
    match long {
        "help" => Some(Command::Help(mode)),
        "version" => Some(Command::Version),
        _ => None,
    }
}

fn lookup_long<'a>(table: &'a [FlagSpec], name: &str) -> Option<&'a FlagSpec> {
    table
        .iter()
        .find(|f| f.long == name || f.aliases.contains(&name))
}

fn lookup_short(table: &[FlagSpec], c: char) -> Option<&FlagSpec> {
    table.iter().find(|f| f.short == Some(c))
}

//! Help pages.
//!
//! The exact column widths, wrapping, and padding of each help page are
//! compatibility output taken verbatim from the binary; they are stored as
//! observed-output fixtures and emitted as opaque strings. `render_help` selects
//! the fixture for a mode.

use crate::modes::Mode;

const HELP_GLOBAL: &str = include_str!("../fixtures/help_global.txt");
const HELP_INTERACTIVE: &str = include_str!("../fixtures/help_interactive.txt");
const HELP_VARIANTS: &str = include_str!("../fixtures/help_variants.txt");
const HELP_TEST: &str = include_str!("../fixtures/help_test.txt");

/// The help page for a mode, byte-for-byte as the binary prints it.
pub fn render_help(mode: Mode) -> &'static str {
    match mode {
        Mode::Batch => HELP_GLOBAL,
        Mode::Interactive => HELP_INTERACTIVE,
        Mode::Variants => HELP_VARIANTS,
        Mode::Test => HELP_TEST,
    }
}

//! Version banner and the maude readiness preamble.
//!
//! In `--version`/`-V` output the maude readiness check and the version banner
//! interleave in a fixed, reproducible order (the banner is printed while the
//! maude subprocess is awaited). The observed byte layout is stored as a template
//! with `{{SLOT}}` markers for the build/runtime metadata; `render_version` fills
//! the slots. The static text of the template is byte-exact observed output.

const VERSION_TEMPLATE: &str = include_str!("../fixtures/version.tmpl");

/// Maude tool identity used in the readiness preamble.
#[derive(Debug, Clone)]
pub struct MaudeInfo {
    /// Tool path as printed inside the quotes (default `maude`).
    pub path: String,
    /// Reported maude version, e.g. `3.5.1`.
    pub version: String,
}

impl Default for MaudeInfo {
    fn default() -> Self {
        MaudeInfo { path: "maude".to_string(), version: "3.5.1".to_string() }
    }
}

/// Build/runtime metadata that fills the version banner slots.
#[derive(Debug, Clone)]
pub struct VersionInfo {
    pub maude: MaudeInfo,
    pub tamarin_version: String,
    pub copyright_years: String,
    /// Everything after `Git revision: ` (revision + dirty note + branch).
    pub git_description: String,
    /// The `Compiled at:` timestamp text.
    pub compiled_at: String,
}

/// The version banner, filling every slot in the observed template.
pub fn render_version(info: &VersionInfo) -> String {
    VERSION_TEMPLATE
        .replace("{{MAUDE_PATH}}", &info.maude.path)
        .replace("{{TAMARIN_VERSION}}", &info.tamarin_version)
        .replace("{{COPYRIGHT_YEARS}}", &info.copyright_years)
        .replace("{{MAUDE_VERSION}}", &info.maude.version)
        .replace("{{GIT_DESCRIPTION}}", &info.git_description)
        .replace("{{COMPILED_AT}}", &info.compiled_at)
}

/// The 3-line maude readiness preamble emitted before batch/variants processing
/// (each line terminated by a newline).
pub fn maude_preamble(maude: &MaudeInfo) -> String {
    format!(
        "maude tool: '{}'\n checking version: {}. OK.\n checking installation: OK.\n",
        maude.path, maude.version
    )
}

//! Batch-mode output framing around an opaque theory payload.
//!
//! The theory pretty-print itself (`theory <name> … end`, including any
//! `WARNING:` block and the `Generated from:` comment) is treated as an opaque
//! payload slot. This module builds everything AROUND it: the maude preamble, the
//! per-theory progress lines, and the "summary of summaries" block.

use crate::version::{maude_preamble, MaudeInfo};

/// Width of the `=` rule that brackets the summary block (observed: 78).
const RULE_WIDTH: usize = 78;

/// Per-theory progress phases, in the order printed for a fully closed theory.
#[derive(Debug, Clone, Copy)]
pub enum Phase {
    Loaded,
    Translated,
    DerivationChecksStarted,
    DerivationChecksEnded,
    Closed,
}

impl Phase {
    fn text(self) -> &'static str {
        match self {
            Phase::Loaded => "Theory loaded",
            Phase::Translated => "Theory translated",
            Phase::DerivationChecksStarted => "Derivation checks started",
            Phase::DerivationChecksEnded => "Derivation checks ended",
            Phase::Closed => "Theory closed",
        }
    }
}

/// The five progress phases a closed theory reports.
pub const CLOSED_PHASES: [Phase; 5] = [
    Phase::Loaded,
    Phase::Translated,
    Phase::DerivationChecksStarted,
    Phase::DerivationChecksEnded,
    Phase::Closed,
];

/// One progress line: `[Theory <name>] <phase>\n`.
pub fn progress_line(theory: &str, phase: Phase) -> String {
    format!("[Theory {}] {}\n", theory, phase.text())
}

fn progress_block(theory: &str, phases: &[Phase]) -> String {
    phases.iter().map(|p| progress_line(theory, *p)).collect()
}

/// Whether a lemma quantifies over all traces or asserts an existing trace.
#[derive(Debug, Clone, Copy)]
pub enum TraceKind {
    AllTraces,
    ExistsTrace,
}

impl TraceKind {
    fn text(self) -> &'static str {
        match self {
            TraceKind::AllTraces => "all-traces",
            TraceKind::ExistsTrace => "exists-trace",
        }
    }
}

/// Per-lemma verdict.
#[derive(Debug, Clone, Copy)]
pub enum LemmaResult {
    Verified,
    Falsified,
    AnalysisIncomplete,
}

impl LemmaResult {
    fn text(self) -> &'static str {
        match self {
            LemmaResult::Verified => "verified",
            LemmaResult::Falsified => "falsified",
            LemmaResult::AnalysisIncomplete => "analysis incomplete",
        }
    }
}

/// One line of the summary body.
#[derive(Debug, Clone)]
pub enum SummaryEntry {
    Lemma { name: String, kind: TraceKind, result: LemmaResult, steps: u64 },
    /// `WARNING: <count> wellformedness check failed!` (note the singular "check").
    Warning { count: u64 },
}

impl SummaryEntry {
    fn text(&self) -> String {
        match self {
            SummaryEntry::Lemma { name, kind, result, steps } => {
                format!("{} ({}): {} ({} steps)", name, kind.text(), result.text(), steps)
            }
            SummaryEntry::Warning { count } => {
                format!("WARNING: {} wellformedness check failed!", count)
            }
        }
    }
}

/// The "summary of summaries" block, bracketed by `=` rules. `processing_time`
/// is rendered as seconds with two decimals (e.g. `0.39s`).
pub fn render_summary(analyzed_path: &str, processing_time: f64, entries: &[SummaryEntry]) -> String {
    let rule = "=".repeat(RULE_WIDTH);
    let mut out = String::new();
    out.push_str(&rule);
    out.push('\n');
    out.push_str("summary of summaries:\n");
    out.push('\n');
    out.push_str(&format!("analyzed: {}\n", analyzed_path));
    out.push('\n');
    out.push_str(&format!("  processing time: {:.2}s\n", processing_time));
    out.push_str("  \n"); // literal two-space separator line
    for e in entries {
        out.push_str(&format!("  {}\n", e.text()));
    }
    out.push('\n');
    out.push_str(&rule);
    out.push('\n');
    out
}

/// Full framing for a processed (closed) theory: maude preamble, the five
/// progress lines, the opaque `payload`, then the summary block. `payload` must
/// be the pretty-printed theory ending with `end\n`.
pub fn frame_processed(
    maude: &MaudeInfo,
    theory: &str,
    payload: &str,
    analyzed_path: &str,
    processing_time: f64,
    entries: &[SummaryEntry],
) -> String {
    let mut out = String::new();
    out.push_str(&maude_preamble(maude));
    out.push_str(&progress_block(theory, &CLOSED_PHASES));
    out.push_str(payload);
    out.push('\n'); // blank line between payload and summary rule
    out.push_str(&render_summary(analyzed_path, processing_time, entries));
    out
}

/// Framing for `--parse-only`: a single `Theory loaded` progress line then the
/// opaque payload. No maude preamble and no summary block.
pub fn frame_parse_only(theory: &str, payload: &str) -> String {
    let mut out = String::new();
    out.push_str(&progress_line(theory, Phase::Loaded));
    out.push_str(payload);
    out
}

//! Error text renderers.
//!
//! Two tiers, both observed to exit 1:
//! - cmdargs-level parse errors, produced by [`crate::parse`] ([`CliError`]).
//! - runtime errors printed after the maude preamble (file-open failures and
//!   application `error` call sites); these are text producers the caller emits
//!   during processing, not parse-time results.
//!
//! Every literal string here is compatibility output copied from observed oracle
//! output (see `workspace/captures/`).

use crate::help::render_help;
use crate::modes::Mode;

/// A ready-to-print error with its exit code (observed: always 1).
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct CliError {
    pub text: String,
    pub exit_code: i32,
}

impl CliError {
    fn code1(text: String) -> Self {
        CliError { text, exit_code: 1 }
    }
}

// ---- cmdargs-level parse errors ----------------------------------------------

/// `Unknown flag: <flag>` (bare one-liner; `flag` includes its dashes).
pub fn unknown_flag(flag: &str) -> CliError {
    CliError::code1(format!("Unknown flag: {}\n", flag))
}

/// `Unhandled argument to flag, none expected: <token>` for a value given to a
/// valueless flag (`token` is the whole `--flag=value`).
pub fn unhandled_argument(token: &str) -> CliError {
    CliError::code1(format!("Unhandled argument to flag, none expected: {}\n", token))
}

/// `Ambiguous mode '<token>', could be any of: <names…>`.
pub fn ambiguous_mode(token: &str, names: &[&str]) -> CliError {
    CliError::code1(format!(
        "Ambiguous mode '{}', could be any of: {}\n",
        token,
        names.join(" ")
    ))
}

/// `error: no input files given` followed by a blank line and the mode's full
/// help page.
pub fn no_input_files(mode: Mode) -> CliError {
    CliError::code1(format!("error: no input files given\n\n{}", render_help(mode)))
}

/// `error: directory '<dir>' does not exist.` followed by a blank line and the
/// mode's full help page. (Interactive WORKDIR check; requires the filesystem,
/// so it is a caller-invoked renderer rather than a parse-time result.)
pub fn directory_does_not_exist(dir: &str, mode: Mode) -> CliError {
    CliError::code1(format!(
        "error: directory '{}' does not exist.\n\n{}",
        dir,
        render_help(mode)
    ))
}

// ---- runtime errors (printed after the maude preamble) -----------------------

/// Reason an input file could not be opened, with its exact message suffix.
#[derive(Debug, Clone, Copy)]
pub enum OpenFileError {
    DoesNotExist,
    PermissionDenied,
    IsDirectory,
}

impl OpenFileError {
    fn suffix(self) -> &'static str {
        match self {
            OpenFileError::DoesNotExist => "openFile: does not exist (No such file or directory)",
            OpenFileError::PermissionDenied => "openFile: permission denied (Permission denied)",
            OpenFileError::IsDirectory => "openFile: inappropriate type (is a directory)",
        }
    }
}

/// `tamarin-prover: <path>: <reason>` — a file-open failure line.
pub fn open_file_error(path: &str, reason: OpenFileError) -> String {
    format!("tamarin-prover: {}: {}\n", path, reason.suffix())
}

/// An application `error` call with the observed Haskell CallStack. `message` is
/// one of the known messages, e.g. `bound: invalid bound given` or
/// `output mode not supported.`.
pub fn app_error(message: &str) -> String {
    format!(
        "tamarin-prover: {}\nCallStack (from HasCallStack):\n  error, called at src/Main/Mode/Batch.hs:162:33 in main:Main.Mode.Batch\n",
        message
    )
}

//! Thin driver exercising the CLI text surface.
//!
//! Handles the pure-text paths (help, version, parse errors) byte-for-byte so
//! they can be verified against the black-box binary. `Run` has no prover engine
//! behind it here — real integration wires the parsed [`cli_clean::RunSpec`] into
//! the prover and uses [`cli_clean::framing`] to wrap its output.

use std::process::exit;

use cli_clean::version::{MaudeInfo, VersionInfo};
use cli_clean::{parse, render_version, Command};

/// Version slots as observed from the reference build. Real integration injects
/// the actual build metadata of the hosting binary.
fn observed_version_info() -> VersionInfo {
    VersionInfo {
        maude: MaudeInfo::default(),
        tamarin_version: "1.13.0".to_string(),
        copyright_years: "2010-2023".to_string(),
        git_description: "0234f6a1abee25677c0accef62de0ac2883b0347 (with uncommited changes), branch: HEAD"
            .to_string(),
        compiled_at: "2026-07-16 18:33:16.036427196 UTC".to_string(),
    }
}

fn main() {
    let argv: Vec<String> = std::env::args().skip(1).collect();
    match parse(&argv) {
        Ok(Command::Help(mode)) => {
            print!("{}", cli_clean::render_help(mode));
            exit(0);
        }
        Ok(Command::Version) => {
            print!("{}", render_version(&observed_version_info()));
            exit(0);
        }
        Ok(Command::Run(spec)) => {
            // Text-surface stub: no prover engine in this crate.
            eprintln!(
                "[cli-clean] parsed: mode={:?} positional={:?} flags={:?}",
                spec.mode, spec.positional, spec.options.flags
            );
            exit(0);
        }
        Err(e) => {
            eprint!("{}", e.text);
            exit(e.exit_code);
        }
    }
}

